channel.postprocessingScript:
// This script executes once after a message has been processed
// Responses returned from here will be stored as "Postprocessor" in the response map




// ---------------------- usage: extract rawResponseMsg, call functions and persist ----------------------

// 1) extract rawResponseMsg safely from responseMap
var destName = 'response_operationoutcome';
var rawResponseMsg = null;
try {
    var destResp = responseMap.get(destName);
    if (destResp) {
        if (typeof destResp.getMessage === 'function') {
            rawResponseMsg = destResp.getMessage();
        } else if (destResp.message !== undefined) {
            rawResponseMsg = destResp.message;
        } else {
            rawResponseMsg = destResp.toString();
        }
    } else {
        logger.info("[CHANNEL: 1115 TECHBD " + channelName + "][INTERACTION ID: " +interactionId +" ]:No response found in responseMap for " + destName);
    }
} catch (e) {
    rawResponseMsg = null;
    try { logger.warn("[CHANNEL: 1115 TECHBD " + channelName + "][INTERACTION ID: " +interactionId +" ]:Error while extracting rawResponseMsg: " + e); } catch(ignore){}
}

return;

